mapper.select:
select e.id, e.url, e.content, ec.name as categoryName, u.nick_name as creatorName, e.create_time, e.status, e.height, e.width from emoji e left join emoji_category ec on e.category_id = ec.id inner join user u on u.id = e.creator_id
and e.id = #{id}
and e.content like concat( #{content},'%')
and e.status = #{status}
and ec.status = 1
and e.category_id = #{categoryId}
and e.creator_id = #{creatorId}
and e.create_time > #{createTime}
and e.status != 0

select e.id, e.url, e.content,e.height,e.width , ec.name as categoryName, u.nick_name as creatorName, e.create_time, e.status from emoji e left join emoji_category ec on e.category_id = ec.id left join user u on u.id = CAST(e.creator_id AS UNSIGNED)
e.status = #{status}
and ec.status = 1
and e.create_time < #{cursor}
and e.create_time > #{cursor}
order by e.create_time
desc
asc

select * from emoji

    id in

         #{item}


       and status = #{status}
